function getHumanAgentStatusMessageText(agentMessageType, responseUserProfile, intl) {
  const name = responseUserProfile?.nickname;
  let messageKey;
  switch (agentMessageType) {
   case HumanAgentMessageType.HUMAN_AGENT_JOINED:
    {
      messageKey = name ? "agent_agentJoinedName" : "agent_agentJoinedNoName";
      break;
    }

   case HumanAgentMessageType.RELOAD_WARNING:
    {
      messageKey = "agent_youConnectedWarning";
      break;
    }

   case HumanAgentMessageType.HUMAN_AGENT_LEFT_CHAT:
    {
      messageKey = name ? "agent_agentLeftChat" : "agent_agentLeftChatNoName";
      break;
    }

   case HumanAgentMessageType.HUMAN_AGENT_ENDED_CHAT:
    {
      messageKey = name ? "agent_agentEndedChat" : "agent_agentEndedChatNoName";
      break;
    }

   case HumanAgentMessageType.TRANSFER_TO_HUMAN_AGENT:
    {
      messageKey = name ? "agent_transferring" : "agent_transferringNoName";
      break;
    }

   case HumanAgentMessageType.USER_ENDED_CHAT:
    {
      messageKey = "agent_youEndedChat";
      break;
    }

   case HumanAgentMessageType.CHAT_WAS_ENDED:
    {
      messageKey = "agent_conversationWasEnded";
      break;
    }

   case HumanAgentMessageType.DISCONNECTED:
    {
      messageKey = "agent_disconnected";
      break;
    }

   case HumanAgentMessageType.RECONNECTED:
    {
      messageKey = "agent_reconnected";
      break;
    }

   case HumanAgentMessageType.SHARING_REQUESTED:
    {
      messageKey = "agent_sharingRequested";
      break;
    }

   case HumanAgentMessageType.SHARING_ACCEPTED:
    {
      messageKey = "agent_sharingAccepted";
      break;
    }

   case HumanAgentMessageType.SHARING_DECLINED:
    {
      messageKey = "agent_sharingDeclined";
      break;
    }

   case HumanAgentMessageType.SHARING_CANCELLED:
    {
      messageKey = "agent_sharingCancelled";
      break;
    }

   case HumanAgentMessageType.SHARING_ENDED:
    {
      messageKey = "agent_sharingEnded";
      break;
    }

   default:
    return "";
  }
  return messageKey && intl.formatMessage({
    id: messageKey
  }, {
    personName: name
  });
}

function toPair(localMessages, originalMessage) {
  return {
    localMessages: localMessages,
    originalMessage: originalMessage
  };
}

async function createHumanAgentLocalMessage(agentMessageType, serviceManager, responseUserProfile, fireEvents = true) {
  const text = getHumanAgentStatusMessageText(agentMessageType, responseUserProfile, serviceManager.intl);
  const result = createHumanAgentLocalMessageForType(agentMessageType);
  const {originalMessage: originalMessage, localMessage: localMessage} = result;
  localMessage.item.text = text;
  if (responseUserProfile) {
    originalMessage.message_options = originalMessage.message_options || {};
    originalMessage.message_options.response_user_profile = responseUserProfile;
  }
  if (fireEvents) {
    await serviceManager.fire({
      type: BusEventType.HUMAN_AGENT_PRE_RECEIVE,
      data: originalMessage
    });
  }
  deepFreeze(originalMessage);
  if (fireEvents) {
    await serviceManager.fire({
      type: BusEventType.HUMAN_AGENT_RECEIVE,
      data: originalMessage
    });
  }
  return result;
}

function createHumanAgentLocalMessageForType(agentMessageType) {
  const messageItem = {
    response_type: MessageResponseTypes.TEXT,
    agent_message_type: agentMessageType
  };
  const originalMessage = createMessageResponseForItem(messageItem);
  const localMessage = outputItemToLocalItem(messageItem, originalMessage);
  return {
    localMessage: localMessage,
    originalMessage: originalMessage
  };
}

function createBotReturnMessage(languagePack) {
  const {agent_botReturned: agent_botReturned} = languagePack;
  if (!agent_botReturned) {
    return null;
  }
  const {originalMessage: originalMessage, localMessage: localMessage} = createHumanAgentLocalMessageForType(null);
  localMessage.item.text = agent_botReturned;
  return {
    originalMessage: originalMessage,
    localMessage: localMessage
  };
}

async function addMessages(messagePairs, showLiveMessages, serviceManager) {
  if (showLiveMessages) {
    await asyncForEach(messagePairs, async ({localMessages: localMessages, originalMessage: originalMessage}) => {
      await asyncForEach(localMessages, async (localMessage, index) => {
        await serviceManager.actions.handleUserDefinedResponseItems(localMessage, originalMessage);
        serviceManager.store.dispatch(actions.addLocalMessageItem(localMessage, originalMessage, index === 0));
      });
    });
  }
}

async function addBotReturnMessage(botReturnDelay, wasSuspended, serviceManager) {
  const botReturn = createBotReturnMessage(serviceManager.store.getState().languagePack);
  if (botReturn) {
    const initialRestartCount = serviceManager.restartCount;
    conditionalSetTimeout(() => {
      if (initialRestartCount === serviceManager.restartCount) {
        addMessages([ toPair([ botReturn.localMessage ], botReturn.originalMessage) ], !wasSuspended, serviceManager);
      }
    }, botReturnDelay);
  }
}

async function addHumanAgentEndChatMessage(agentMessageType, responseUserProfile, fireEvents, wasSuspended, serviceManager) {
  const endChatMessage = await createHumanAgentLocalMessage(agentMessageType, serviceManager, responseUserProfile, fireEvents);
  await addMessages([ toPair([ endChatMessage.localMessage ], endChatMessage.originalMessage) ], !wasSuspended, serviceManager);
}

